from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Generate a natural‑language description from a list of triples."""
    if not triples:
        return ""

    # helper to strip surrounding quotes
    def clean(val: str) -> str:
        return val.strip('\"')

    # group triples by subject to avoid repeating the subject many times
    grouped: dict[str, list[Triple]] = {}
    for t in triples:
        grouped.setdefault(t.subject, []).append(t)

    sentences: list[str] = []

    # ------------------------------------------------------------------
    # Helper: order clauses so that instrument, band, then genre appear first
    # ------------------------------------------------------------------
    clause_order = {
        "instrument": 0,
        "associatedBand/associatedMusicalArtist": 1,
        "genre": 2,
        "background": 3,
        "occupation": 4,
        "origin": 5,
        "birthDate": 6,
        "birthYear": 6,
        "birthPlace": 6,
        "deathDate": 7,
        "deathPlace": 7,
        "nationality": 8,
        "recordLabel": 9,
        "activeYearsStartYear": 10,
        "activeYearsEndYear": 11,
        "country": 12,
        "capital": 13,
        "isPartOf": 14,
        "language": 15,
        "officialLanguage": 15,
        "derivative": 16,
        "stylisticOrigin": 17,
    }

    for subj, group in grouped.items():
        # collect clause fragments for this subject together with their predicate
        # Group objects by predicate to enable natural conjunctions
        pred_objects: dict[str, list[str]] = {}
        for t in group:
            p, o = t.predicate, clean(t.object)
            pred_objects.setdefault(p, []).append(o)

        # Helper to join a list with commas and "and" for the last element
        def join_list(items: list[str]) -> str:
            if not items:
                return ""
            if len(items) == 1:
                return items[0]
            return ", ".join(items[:-1]) + " and " + items[-1]

        # Build ordered clause fragments
        raw_clauses: list[tuple[int, str]] = []
        for p, objs in pred_objects.items():
            o_joined = join_list(objs)
            order = clause_order.get(p, 99)

            if p == "birthDate":
                raw_clauses.append((order, f"was born on {o_joined}"))
            elif p == "birthYear":
                raw_clauses.append((order, f"was born in {o_joined}"))
            elif p == "birthPlace":
                raw_clauses.append((order, f"was born in {o_joined}"))
            elif p == "deathDate":
                raw_clauses.append((order, f"died on {o_joined}"))
            elif p == "deathPlace":
                raw_clauses.append((order, f"died in {o_joined}"))
            elif p == "origin":
                raw_clauses.append((order, f"originates from {o_joined}"))
            elif p == "genre":
                # Use more natural phrasing for genre
                raw_clauses.append((order, f"genre is {o_joined}"))
            elif p == "instrument":
                raw_clauses.append((order, f"plays the {o_joined}"))
            elif p in {"occupation", "background"}:
                raw_clauses.append((order, f"is a {o_joined}"))
            elif p == "associatedBand/associatedMusicalArtist":
                raw_clauses.append((order, f"is associated with {o_joined}"))
            elif p == "recordLabel":
                raw_clauses.append((order, f"is signed to {o_joined}"))
            elif p == "activeYearsStartYear":
                raw_clauses.append((order, f"started their career in {o_joined}"))
            elif p == "activeYearsEndYear":
                raw_clauses.append((order, f"ended their career in {o_joined}"))
            elif p == "nationality":
                raw_clauses.append((order, f"is {o_joined}"))
            elif p == "capital":
                raw_clauses.append((order, f"has capital {o_joined}"))
            elif p == "country":
                raw_clauses.append((order, f"is in {o_joined}"))
            elif p == "isPartOf":
                raw_clauses.append((order, f"is part of {o_joined}"))
            elif p in {"language", "officialLanguage"}:
                raw_clauses.append((order, f"speaks {o_joined}"))
            elif p == "derivative":
                raw_clauses.append((order, f"has derivative {o_joined}"))
            elif p == "stylisticOrigin":
                raw_clauses.append((order, f"originated from {o_joined}"))
            else:
                raw_clauses.append((order, f"{p} {o_joined}"))

        # sort clauses by the predefined order
        raw_clauses.sort(key=lambda x: x[0])
        clauses = [c for _, c in raw_clauses]

        # Build the sentence for this subject
        if not clauses:
            continue
        if len(clauses) == 1:
            sentence = f"{subj} {clauses[0]}."
        else:
            sentence = f"{subj} " + ", ".join(clauses[:-1]) + ", and " + clauses[-1] + "."
        sentences.append(sentence)

    # ------------------------------------------------------------------
    # Additional sentences for genre‑relationship predicates
    # ------------------------------------------------------------------
    genre_predicates = {
        "musicFusionGenre": lambda s, o: f"{o} is a musical fusion of {s}.",
        "musicSubgenre": lambda s, o: f"{o} is a sub‑genre of {s}.",
        "derivative": lambda s, o: f"{o} is a derivative of {s}.",
        "stylisticOrigin": lambda s, o: f"{o} originated from {s}.",
    }

    for t in triples:
        if t.predicate in genre_predicates:
            # avoid duplicating sentences already created for person subjects
            if t.subject not in grouped:
                sentences.append(genre_predicates[t.predicate](t.subject, clean(t.object)))

    # Combine sentences for different subjects into one paragraph
    return " ".join(sentences)

# EVOLVE-BLOCK-END

